    <div class="section">
        <h2>Store Information</h2>
        <p><strong>Address:</strong> 123 Main Street, Yourtown</p>
        <p><strong>Open:</strong> Mon–Sat 8:00am–8:00pm, Sun 10:00am–6:00pm</p>
        <p><strong>Phone:</strong> (555) 123-4567</p>
